{"filePath":"d:\__MY APPS\ad free podcast player\apps\server\windows\run-wamp-triggered-bridge.ps1","content":"param(
    [Parameter(Mandatory = $true)]
    [string]$RemoteHost,

    [Parameter(Mandatory = $true)]
    [string]$RemoteUser,

    [int]$RemoteSshPort = 22,
    [int]$RemoteBindPort = 8081,
    [string]$RemoteBindHost = '127.0.0.1',
    [int]$LocalHttpPort = 80,
    [string]$IdentityFile = '',
    [switch]$BatchMode,
    [int]$PollSeconds = 3
)

$ErrorActionPreference = 'Stop'

$bridgeScript = Join-Path $PSScriptRoot 'run-local-bridge.ps1'
if (-not (Test-Path $bridgeScript)) {
    throw "run-local-bridge.ps1 not found at $bridgeScript"
}

function Test-HttpPort {
    param([int]$Port)

    try {
        $listener = New-Object System.Net.Sockets.TcpClient
        $iar = $listener.BeginConnect('127.0.0.1', $Port, $null, $null)
        $ok = $iar.AsyncWaitHandle.WaitOne(750)
        if ($ok -and $listener.Connected) {
            $listener.EndConnect($iar) | Out-Null
            $listener.Close()
            return $true
        }
        $listener.Close()
        return $false
    } catch {
        return $false
    }
}

$bridgeProc = $null

while ($true) {
    $wampUp = Test-HttpPort -Port $LocalHttpPort

    if ($wampUp) {
        if ($null -eq $bridgeProc -or $bridgeProc.HasExited) {
            $args = @(
                '-NoProfile',
                '-ExecutionPolicy', 'Bypass',
                '-File', '"' + $bridgeScript + '"',
                '-RemoteHost', '"' + $RemoteHost + '"',
                '-RemoteUser', '"' + $RemoteUser + '"',
                '-RemoteSshPort', "$RemoteSshPort",
                '-RemoteBindPort', "$RemoteBindPort",
                '-RemoteBindHost', '"' + $RemoteBindHost + '"',
                '-LocalHttpPort', "$LocalHttpPort",
                '-SkipWampStart'
            )

            if ($IdentityFile -ne '') {
                $args += @('-IdentityFile', '"' + $IdentityFile + '"')
            }

            if ($BatchMode) {
                $args += '-BatchMode'
            }

            $bridgeProc = Start-Process -FilePath 'powershell.exe' -ArgumentList ($args -join ' ') -WindowStyle Hidden -PassThru
            Write-Host "WAMP detected on localhost:$LocalHttpPort; started bridge process PID $($bridgeProc.Id)."
        }
    } else {
        if ($null -ne $bridgeProc -and -not $bridgeProc.HasExited) {
            Stop-Process -Id $bridgeProc.Id -Force -ErrorAction SilentlyContinue
            Write-Host "WAMP unavailable on localhost:$LocalHttpPort; stopped bridge process PID $($bridgeProc.Id)."
        }
        $bridgeProc = $null
    }

    Start-Sleep -Seconds $PollSeconds
}
"}

